#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void lud_omp(float *m, int matrix_dim) {
    int i, j, k, offset, bx, by, tx, ty, idx;
    int array_offset, global_row_id, global_col_id;
    float sum;
    float *shadow, *dia, *peri_row, *peri_col;

    // Allocate temporary buffers (equivalent to __local memory in OpenCL)
    shadow = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
    dia = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
    peri_row = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
    peri_col = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));

    // Main iteration over diagonal blocks
    for (offset = 0; offset < matrix_dim - BLOCK_SIZE; offset += BLOCK_SIZE) {

        // lud_diagonal: Process diagonal block
        {
            // Copy diagonal block to shadow
            array_offset = offset * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
                }
                array_offset += matrix_dim;
            }

            // Process diagonal block (LU decomposition)
            for (i = 0; i < BLOCK_SIZE - 1; i++) {
                for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
                    for (j = 0; j < i; j++) {
                        shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
                    }
                    shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
                }

                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    for (j = 0; j < i + 1; j++) {
                        shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
                    }
                }
            }

            // Copy back to m
            array_offset = (offset + 1) * matrix_dim + offset;
            for (i = 1; i < BLOCK_SIZE; i++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
                }
                array_offset += matrix_dim;
            }
        }

        // lud_perimeter: Process perimeter blocks
        for (bx = 0; bx < (matrix_dim - offset) / BLOCK_SIZE - 1; bx++) {
            // Load diagonal data (first half)
            array_offset = offset * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE / 2; i++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    dia[i * BLOCK_SIZE + tx] = m[array_offset + tx];
                }
                array_offset += matrix_dim;
            }

            // Load diagonal data (second half)
            array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
            for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    dia[i * BLOCK_SIZE + tx] = m[array_offset + tx];
                }
                array_offset += matrix_dim;
            }

            // Load peri_row data
            array_offset = offset * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    peri_row[i * BLOCK_SIZE + tx] = m[array_offset + (bx + 1) * BLOCK_SIZE + tx];
                }
                array_offset += matrix_dim;
            }

            // Load peri_col data
            array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    peri_col[i * BLOCK_SIZE + tx] = m[array_offset + tx];
                }
                array_offset += matrix_dim;
            }

            // Process peri_row
            for (i = 1; i < BLOCK_SIZE; i++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    for (j = 0; j < i; j++) {
                        peri_row[i * BLOCK_SIZE + tx] -= dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + tx];
                    }
                }
            }

            // Process peri_col
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    for (j = 0; j < i; j++) {
                        peri_col[i * BLOCK_SIZE + tx] -= peri_col[j * BLOCK_SIZE + tx] * dia[j * BLOCK_SIZE + i];
                    }
                    peri_col[i * BLOCK_SIZE + tx] /= dia[i * BLOCK_SIZE + i];
                }
            }

            // Write back peri_row
            array_offset = (offset + 1) * matrix_dim + offset;
            for (i = 1; i < BLOCK_SIZE; i++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    m[array_offset + (bx + 1) * BLOCK_SIZE + tx] = peri_row[i * BLOCK_SIZE + tx];
                }
                array_offset += matrix_dim;
            }

            // Write back peri_col
            array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    m[array_offset + tx] = peri_col[i * BLOCK_SIZE + tx];
                }
                array_offset += matrix_dim;
            }
        }

        // lud_internal: Process internal blocks
        #pragma omp parallel for collapse(2)
        for (by = 0; by < (matrix_dim - offset) / BLOCK_SIZE - 1; by++) {
            for (bx = 0; bx < (matrix_dim - offset) / BLOCK_SIZE - 1; bx++) {
                global_row_id = offset + (by + 1) * BLOCK_SIZE;
                global_col_id = offset + (bx + 1) * BLOCK_SIZE;

                // Load perimeter data
                for (ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (tx = 0; tx < BLOCK_SIZE; tx++) {
                        peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
                        peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];
                    }
                }

                // Process internal block
                for (ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (tx = 0; tx < BLOCK_SIZE; tx++) {
                        sum = 0;
                        for (k = 0; k < BLOCK_SIZE; k++) {
                            sum += peri_col[ty * BLOCK_SIZE + k] * peri_row[k * BLOCK_SIZE + tx];
                        }
                        m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                    }
                }
            }
        }
    }

    // Process last diagonal block
    {
        offset = matrix_dim - BLOCK_SIZE;

        // Copy diagonal block to shadow
        array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
            }
            array_offset += matrix_dim;
        }

        // Process diagonal block
        for (i = 0; i < BLOCK_SIZE - 1; i++) {
            for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
                for (j = 0; j < i; j++) {
                    shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
                }
                shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
            }

            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                for (j = 0; j < i + 1; j++) {
                    shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
                }
            }
        }

        // Copy back
        array_offset = (offset + 1) * matrix_dim + offset;
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
            }
            array_offset += matrix_dim;
        }
    }

    // Free temporary buffers
    free(shadow);
    free(dia);
    free(peri_row);
    free(peri_col);
}
